/// Compute REML objective function for variance component optimization
/// Using lme4's profiled REML approach with θ = σ_u/σ_e parameterization
fn compute_reml_objective(
    theta: &Array1<f64>,
    x: &ArrayView2<f64>,
    z: &CsMat<f64>,
    y: &ArrayView1<f64>,
    group_sizes: &Array1<f64>,
    config: &PirlsConfig,
) -> Result<f64, OptimError> {
    let n_obs = y.len();
    let n_fixed = x.ncols();

    // New parameterization: optimize over log(θ) where θ = σ_u/σ_e
    // This eliminates σ_e through profiling
    let log_theta = theta[0];
    let theta_ratio = log_theta.exp();
    let theta_ratio_sq = theta_ratio * theta_ratio;

    // For profiled REML, we need pwrss at this θ value
    // We'll use σ_e = 1 initially and scale later
    let variances = Array1::from(vec![theta_ratio_sq, 1.0]);

    // Run PIRLS to convergence with current variance ratio
    let pirls_result = pirls_for_reml(x, z, y, &variances, config)?;

    // Calculate log|L_θᵀL_θ| for profiled REML
    // For random intercept model: log|θ² Z'Z + I|
    // This simplifies to: Σ log(θ² * n_j + 1) where n_j is group j size
    let log_det_penalty: f64 = group_sizes
        .iter()
        .map(|&n_j| (theta_ratio_sq * n_j + 1.0).ln())
        .sum();

    // Compute REML deviance using lme4's profiled formula
    // d_REML(θ) = log|L_θᵀL_θ| + (n-p) * [1 + log(2π * pwrss(θ) / (n-p))]
    let n_p = (n_obs - n_fixed) as f64;
    let pwrss_term = pirls_result.pwrss / n_p;
    let reml_deviance = log_det_penalty + 
                       n_p * (1.0 + (2.0 * std::f64::consts::PI * pwrss_term).ln());

    Ok(reml_deviance)
}

